// CSS module declarations for Next.js bundler mode
declare module '*.css' {
  const styles: Record<string, string>;
  export default styles;
}
declare module '*.module.css' {
  const styles: Record<string, string>;
  export default styles;
}
declare module '*.module.scss' {
  const styles: Record<string, string>;
  export default styles;
}
declare module '*.module.sass' {
  const styles: Record<string, string>;
  export default styles;
}


